 '{"client_name":"Hotel Maison Ondara (Alicante)","before":{"reservas_directas_mes":12,"comision_Booking_mes":"4.800€","web_conversion":"0.8%"},"after":{"reservas_directas_mes":67,"comision_Booking_mes":"1.900€","web_conversion":"3.4%"},"quote":"Ahorramos 2.900€ al mes solo en comisiones Booking. El programa socio VIP convirtio 40% de clientes Booking en directos.","disclaimer":"Simulacion basada en promedio hotel boutique PACAME primeros 180 dias"}'::jsonb,
 349900, 21,
 '[{"q":"¿Integrais con channel manager si ya tenemos?","a":"Si: Siteminder, Cloudbeds, Mews, Hotelogix. Sincronizacion inventario bidireccional 24/7."},{"q":"¿Cuanto ahorramos en comisiones Booking?","a":"Clientes promedio ahorran 40-60% via reservas directas tras 6 meses. En hoteles 30+ hab, son 5.000-15.000€/mes en comisiones."},{"q":"¿Programa socio VIP como se configura?","a":"Cliente reserva directa = automaticamente socio. Beneficios: 10% off, upgrade sujeto disponibilidad, early check-in, welcome drink."},{"q":"¿Multi-idioma con traducciones automaticas?","a":"No automaticas. Incluimos traduccion profesional ES/EN/FR/DE por copywriter nativo (no Google Translate)."},{"q":"¿Geo-pricing que es?","a":"Precios diferenciados por pais origen (visitante UK ve £, frances ve precio EUR con ajuste tipo cambio)."},{"q":"¿Podemos vender extras (spa, desayuno)?","a":"Si. Upsell en checkout + en email pre-stay. Cross-sell aumenta ticket medio ~30%."},{"q":"¿Reviews centralizadas como?","a":"Widget que muestra reviews top de TripAdvisor + Google + Booking. Cliente ve score agregado (ej 4.7/5 de 450 reviews)."},{"q":"¿Y si ya tengo web?","a":"Migramos todo sin perder SEO (301 redirects + sitemap nuevo). Lanzamos en subdominio stage primero."}]'::jsonb,
 '/verticals/hotel.png',
 'Web para hotel boutique con motor reservas directo · PACAME · desde 3.499€',
